import React, { useState } from "react";

export default function WithdrawalScreen({ onClose, onWithdraw, balance }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    if (!amount || parseFloat(amount) <= 0) {
      alert("Enter a valid amount");
      return;
    }
    if (parseFloat(amount) > balance) {
      alert("Insufficient balance");
      return;
    }
    onWithdraw(parseFloat(amount));
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/30 flex items-center justify-center z-50">
      <div className="bg-white rounded-2xl p-6 w-80">
        <h2 className="text-xl font-bold mb-4">Withdraw Funds</h2>
        <input
          type="number"
          placeholder="Amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="w-full p-3 border rounded-xl mb-4"
        />
        <div className="flex justify-end gap-3">
          <button onClick={onClose} className="py-2 px-4 rounded-xl bg-gray-200 hover:bg-gray-300">Cancel</button>
          <button
            onClick={handleWithdraw}
            className="py-2 px-4 rounded-xl bg-red-600 text-white hover:bg-red-700"
          >
            Withdraw
          </button>
        </div>
      </div>
    </div>
  );
}
